'use strict';

const { allTickets, saveTickets } = require('../core/tickets.js');
const { allComments, saveComments } = require('../core/comments.js');
const { AppError } = require('../lib/errors.js');
const { daysBetween } = require('../lib/dates.js');
const config = require('../config.js');

function purgStale(args) {
  const apply = args.includes('--apply');
  const otherArgs = args.filter((a) => a !== '--apply');

  if (otherArgs.length > 0) {
    throw new AppError('usage: purge-stale [--apply]', 2);
  }

  const tickets = allTickets();
  const comments = allComments();

  // Identify stale tickets: closed AND older than retention window
  const staleTicketIds = new Set();
  const ticketPlan = [];

  for (const ticket of tickets) {
    if (
      ticket.status === 'closed' &&
      daysBetween(ticket.updatedAt, config.referenceDate) > config.retentionDays
    ) {
      staleTicketIds.add(ticket.id);
      ticketPlan.push(ticket.id);
    }
  }

  // Identify comments on stale tickets (cascade)
  const commentPlan = [];
  for (const comment of comments) {
    if (staleTicketIds.has(comment.ticketId)) {
      commentPlan.push(comment.id);
    }
  }

  const totalRemoving = ticketPlan.length + commentPlan.length;

  if (totalRemoving === 0) {
    return { lines: ['total: 0'], exitCode: 3 };
  }

  const lines = [];

  // Print plan
  for (const ticketId of ticketPlan) {
    lines.push(`plan: purge ticket ${ticketId}`);
  }
  for (const commentId of commentPlan) {
    lines.push(`plan: purge comment ${commentId}`);
  }

  // Apply if requested
  if (apply) {
    const newTickets = tickets.filter((t) => !staleTicketIds.has(t.id));
    const newComments = comments.filter((c) => !staleTicketIds.has(c.ticketId));

    saveTickets(newTickets);
    saveComments(newComments);

    lines.push(`applied: ${totalRemoving}`);
  } else {
    lines.push(`total: ${totalRemoving}`);
  }

  return lines;
}

module.exports = { purgStale };

